        if lhs.handle != rhs.handle {
            return false
        }
        if lhs.canonical != rhs.canonical {
            return false
        }
        if lhs.alias != rhs.alias {
            return false
        }
        if lhs.scriptPubkey != rhs.scriptPubkey {
            return false
        }
        if lhs.numId != rhs.numId {
            return false
        }
        if lhs.records != rhs.records {
            return false
        }
        if lhs.fallbackRecords != rhs.fallbackRecords {
            return false
        }
        if lhs.delegate != rhs.delegate {
            return false
        }
        if lhs.commitment != rhs.commitment {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(anchor)
        hasher.combine(sovereignty)
        hasher.combine(handle)
        hasher.combine(canonical)
        hasher.combine(alias)
        hasher.combine(scriptPubkey)
        hasher.combine(numId)
        hasher.combine(records)
        hasher.combine(fallbackRecords)
        hasher.combine(delegate)
        hasher.combine(commitment)
    }
}



